import org.junit.jupiter.api.Test;
import java.util.List;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void multiDigitNumbers() {
        assertEquals(List.of("12", "+", "34", "*", "5"),
                new Solution().tokenize("12+34*5"));
    }

    @Test
    void multiDigitAtEnd() {
        assertEquals(List.of("3", "+", "42"),
                new Solution().tokenize("3+42"));
    }

    @Test
    void singleNumber() {
        assertEquals(List.of("7"),
                new Solution().tokenize("7"));
    }

    @Test
    void emptyInput() {
        assertEquals(List.of(),
                new Solution().tokenize(""));
    }

    @Test
    void allOperatorsAndSingleDigits() {
        assertEquals(List.of("1", "+", "2", "-", "3"),
                new Solution().tokenize("1+2-3"));
    }

    @Test
    void largeNumberAlone() {
        assertEquals(List.of("1000"),
                new Solution().tokenize("1000"));
    }

    @Test
    void twoLargeNumbers() {
        assertEquals(List.of("100", "/", "25"),
                new Solution().tokenize("100/25"));
    }
}
